import React, { useState } from "react";
import "../styles/Contact.css";

const Contact = () => {
  // Form states
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    phoneNumber: "",
    subject: "",
    message: "",
  });
  
  // Auth states
  const [authData, setAuthData] = useState({
    username: "",
    email: "",
    password: "",
    confirmPassword: ""
  });
  
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);
  const [errors, setErrors] = useState({});
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showSignUp, setShowSignUp] = useState(false);

  // Handle form input changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  // Handle auth input changes
  const handleAuthChange = (e) => {
    const { name, value } = e.target;
    setAuthData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  // Handle login
  const handleLogin = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setErrors({});
    
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // In a real app, you would verify credentials with your backend
      setIsLoggedIn(true);
      setSubmitStatus("success");
    } catch (err) {
      setErrors({ general: "Invalid credentials" });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Handle signup
  const handleSignup = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setErrors({});
    
    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      // In a real app, you would register the user
      setIsLoggedIn(true);
      setSubmitStatus("success");
      setShowSignUp(false);
    } catch (err) {
      if (err.response && err.response.data.errors) {
        setErrors(err.response.data.errors);
      } else {
        setErrors({ general: "Registration failed" });
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  // Handle contact form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setErrors({});
    
    try {
      const response = await fetch("https://localhost:7235/api/contact", {
        method: "POST",
        headers: { 
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          FullName: formData.fullName,
          Email: formData.email,
          PhoneNumber: formData.phoneNumber,
          Subject: formData.subject,
          Message: formData.message
        }),
      });

      const data = await response.json();
      
      if (!response.ok) {
        if (data.errors) {
          setErrors(data.errors);
        } else {
          throw new Error(data.title || "Request failed");
        }
        return;
      }

      setSubmitStatus("success");
      setFormData({
        fullName: "",
        email: "",
        phoneNumber: "",
        subject: "",
        message: "",
      });
    } catch (error) {
      setErrors({ general: error.message });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Helper to display field errors
  const renderFieldError = (fieldName) => {
    return errors[fieldName] ? (
      <div className="field-error">{errors[fieldName][0]}</div>
    ) : null;
  };

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.146201882546!2d44.62674911141569!3d40.18355967135914!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa5fb2d2aeb97%3A0x7a90e13129b8e750!2z1Y7VuNaC1aTVvSDUv9Wl1bbVv9aA1bjVtg!5e0!3m2!1shy!2sam!4v1743157411782!5m2!1shy!2sam"
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>Armenia, Yerevan City</p>
              <p>Woods Centre</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          {isLoggedIn ? (
            <>
              <h3>LEAVE US A MESSAGE</h3>
              
              {errors.general && (
                <div className="error-message">
                  ❌ {errors.general}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Thank you! Your message has been sent.
                </div>
              )}

              <form onSubmit={handleSubmit}>
                <input
                  type="text"
                  name="fullName"
                  placeholder="Your Full Name"
                  value={formData.fullName}
                  onChange={handleChange}
                  required
                />
                {renderFieldError("FullName")}
                
                <input
                  type="email"
                  name="email"
                  placeholder="example@email.com"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
                {renderFieldError("Email")}
                
                <input
                  type="tel"
                  name="phoneNumber"
                  placeholder="012 34 56 78"
                  value={formData.phoneNumber}
                  onChange={handleChange}
                  required
                />
                {renderFieldError("PhoneNumber")}
                
                <input
                  type="text"
                  name="subject"
                  placeholder="Subject"
                  value={formData.subject}
                  onChange={handleChange}
                  required
                />
                {renderFieldError("Subject")}
                
                <textarea
                  name="message"
                  placeholder="Write your message here..."
                  value={formData.message}
                  onChange={handleChange}
                  required
                ></textarea>
                {renderFieldError("Message")}

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Sending...
                    </>
                  ) : (
                    "Submit"
                  )}
                </button>
              </form>
            </>
          ) : showSignUp ? (
            <>
              <h3>SIGN UP</h3>
              
              {errors.general && (
                <div className="error-message">
                  ❌ {errors.general}
                </div>
              )}

              <form onSubmit={handleSignup}>
                <input
                  type="text"
                  name="username"
                  placeholder="Username"
                  value={authData.username}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("username")}
                
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("email")}
                
                <input
                  type="password"
                  name="password"
                  placeholder="Password"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("password")}
                
                <input
                  type="password"
                  name="confirmPassword"
                  placeholder="Confirm Password"
                  value={authData.confirmPassword}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("confirmPassword")}

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing Up...
                    </>
                  ) : (
                    "Sign Up"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Already have an account? 
                <button onClick={() => setShowSignUp(false)}>Sign In</button>
              </p>
            </>
          ) : (
            <>
              <h3>SIGN IN</h3>
              
              {errors.general && (
                <div className="error-message">
                  ❌ {errors.general}
                </div>
              )}

              <form onSubmit={handleLogin}>
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("email")}
                
                <input
                  type="password"
                  name="password"
                  placeholder="Password"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />
                {renderFieldError("password")}

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing In...
                    </>
                  ) : (
                    "Sign In"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Don't have an account? 
                <button onClick={() => setShowSignUp(true)}>Sign Up</button>
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Contact;
